import os

def build_environment_aware_prompt(base_prompt: str) -> str:
    env = os.environ.get("DEPLOYMENT_ENV", "unknown")
    is_prod = env == "production"

    env_block = f"""
ENVIRONMENT: {env.upper()}
{'=' * 40}
{'WARNING: You are operating in PRODUCTION. All changes are real and may be irreversible.' if is_prod else 'You are in a non-production environment. Changes are safe to make.'}

{'PRODUCTION RULES:' if is_prod else 'DEVELOPMENT RULES:'}
{'- Confirm with the user before any write, delete, or deploy operation.' if is_prod else '- Proceed with operations as instructed.'}
{'- Never truncate, drop, or migrate production databases without explicit approval.' if is_prod else ''}
{'- Log every action to the audit trail before executing.' if is_prod else ''}
"""
    return env_block.strip() + "\n\n" + base_prompt

# The environment block is injected at runtime, not hardcoded in the base prompt
PROD_SYSTEM_PROMPT = build_environment_aware_prompt(
    "You are a database maintenance agent. Perform the requested maintenance tasks."
)

import time
from collections import defaultdict

class RateLimiter:
    """Token-bucket rate limiter for irreversible tool calls."""
    def __init__(self, limits: dict[str, tuple[int, float]]):
        # limits: {tool_name: (max_calls, window_seconds)}
        self._limits = limits
        self._calls: dict[str, list[float]] = defaultdict(list)

    def check(self, tool_name: str) -> bool:
        if tool_name not in self._limits:
            return True  # no limit defined
        max_calls, window = self._limits[tool_name]
        now = time.time()
        # Purge expired entries
        self._calls[tool_name] = [
            t for t in self._calls[tool_name] if now - t < window
        ]
        if len(self._calls[tool_name]) >= max_calls:
            return False
        self._calls[tool_name].append(now)
        return True

AUTONOMOUS_AGENT_LIMITS = RateLimiter({
    "send_email":    (5,  3600),   # 5 emails per hour
    "deploy":        (1,  1800),   # 1 deploy per 30 minutes
    "delete_file":   (10, 3600),   # 10 deletes per hour
    "git_push":      (3,  600),    # 3 pushes per 10 minutes
})

def guarded_execute(tool_name: str, arguments: dict, executor,
                     limiter: RateLimiter, dry_run: bool = False) -> dict:
    if not limiter.check(tool_name):
        return {"status": "rate_limited", "tool": tool_name}
    if dry_run:
        return {"status": "dry_run", "tool": tool_name, "args": arguments}
    return executor(tool_name, arguments)
